{"code": "import json

# Read the query result from storage
review_result = locals()['var_functions.query_db:10']

# Extract business_ref values and convert to business_id format
business_ids = []
for item in review_result:
    if 'business_ref' in item:
        business_id = item['business_ref'].replace('businessref_', 'businessid_')
        business_ids.append(business_id)

# Build the MongoDB query
mongodb_query = {
    "collection": "business",
    "filter": {
        "business_id": {"$in": business_ids},
        "$or": [
            {"attributes.BusinessParking": {"$exists": True, "$ne": None}},
            {"attributes.BikeParking": {"$exists": True, "$ne": None}}
        ]
    },
    "projection": {"business_id": 1, "attributes": 1, "_id": 0}
}

print('__RESULT__:')
print(json.dumps(mongodb_query))"}

